import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '@/lib/products';

function formatPrice(price: number) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0
  }).format(price);
}

export default async function Page() {
  const products = await getCachedProducts();
  const totalValue = products.reduce((sum, product) => sum + product.price, 0);

  return (
    <main
      style={{
        minHeight: '100vh',
        background:
          'radial-gradient(circle at top left, #f5efe4 0, #f8fafc 36%, #e8eef8 100%)',
        color: '#0f172a',
        padding: '48px 24px'
      }}
    >
      <div style={{ maxWidth: 1120, margin: '0 auto' }}>
        <section
          style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: 24,
            alignItems: 'end',
            justifyContent: 'space-between',
            marginBottom: 28
          }}
        >
          <div style={{ maxWidth: 680 }}>
            <p
              style={{
                margin: 0,
                textTransform: 'uppercase',
                letterSpacing: '0.16em',
                fontSize: 12,
                fontWeight: 700,
                color: '#475569'
              }}
            >
              Admin catalog
            </p>
            <h1
              style={{
                margin: '12px 0 14px',
                fontSize: 'clamp(2.25rem, 5vw, 4.5rem)',
                lineHeight: 0.95,
                letterSpacing: '-0.05em'
              }}
            >
              Product catalog, cached for fast browsing.
            </h1>
            <p
              style={{
                margin: 0,
                maxWidth: 620,
                fontSize: 18,
                lineHeight: 1.6,
                color: '#334155'
              }}
            >
              Operators can browse a stable, read-heavy catalog without paying a fresh query on every request. When ERP or
              PIM data changes, trigger a background refresh and keep working.
            </p>
          </div>

          <form
            action={async () => {
              'use server';
              revalidateTag('products', 'max');
            }}
          >
            <button
              type="submit"
              style={{
                border: 'none',
                borderRadius: 999,
                padding: '14px 20px',
                background: '#0f172a',
                color: '#fff',
                fontSize: 15,
                fontWeight: 700,
                boxShadow: '0 18px 40px rgba(15, 23, 42, 0.18)',
                cursor: 'pointer'
              }}
            >
              Sync latest catalog
            </button>
          </form>
        </section>

        <section
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
            gap: 16,
            marginBottom: 24
          }}
        >
          <StatCard label="Cached SKUs" value={String(products.length)} helper="Served from the shared products cache." />
          <StatCard label="Catalog value" value={formatPrice(totalValue)} helper="Simple snapshot for the admin dashboard." />
          <StatCard label="Invalidation" value="products" helper="One tag refreshes every catalog-dependent view." />
        </section>

        <section
          style={{
            background: 'rgba(255, 255, 255, 0.78)',
            backdropFilter: 'blur(12px)',
            border: '1px solid rgba(148, 163, 184, 0.22)',
            borderRadius: 28,
            overflow: 'hidden',
            boxShadow: '0 30px 80px rgba(15, 23, 42, 0.08)'
          }}
        >
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: '1.2fr 0.5fr 0.5fr',
              gap: 12,
              padding: '18px 22px',
              background: 'rgba(248, 250, 252, 0.96)',
              borderBottom: '1px solid rgba(148, 163, 184, 0.18)',
              fontSize: 13,
              fontWeight: 700,
              textTransform: 'uppercase',
              letterSpacing: '0.08em',
              color: '#64748b'
            }}
          >
            <span>Product</span>
            <span>Price</span>
            <span>Status</span>
          </div>

          <div>
            {products.map(product => (
              <div
                key={product.id}
                style={{
                  display: 'grid',
                  gridTemplateColumns: '1.2fr 0.5fr 0.5fr',
                  gap: 12,
                  padding: '18px 22px',
                  alignItems: 'center',
                  borderBottom: '1px solid rgba(226, 232, 240, 0.8)'
                }}
              >
                <div>
                  <div style={{ fontSize: 16, fontWeight: 700 }}>{product.name}</div>
                  <div style={{ fontSize: 13, color: '#64748b' }}>SKU {product.id.toString().padStart(4, '0')}</div>
                </div>
                <div style={{ fontSize: 16, fontWeight: 600 }}>{formatPrice(product.price)}</div>
                <div>
                  <span
                    style={{
                      display: 'inline-flex',
                      alignItems: 'center',
                      borderRadius: 999,
                      padding: '6px 10px',
                      background: '#dcfce7',
                      color: '#166534',
                      fontSize: 13,
                      fontWeight: 700
                    }}
                  >
                    Live in cache
                  </span>
                </div>
              </div>
            ))}
          </div>
        </section>
      </div>
    </main>
  );
}

function StatCard({
  label,
  value,
  helper
}: {
  label: string;
  value: string;
  helper: string;
}) {
  return (
    <div
      style={{
        borderRadius: 24,
        padding: 20,
        background: 'rgba(255, 255, 255, 0.72)',
        border: '1px solid rgba(148, 163, 184, 0.18)',
        boxShadow: '0 18px 42px rgba(15, 23, 42, 0.06)'
      }}
    >
      <div style={{ fontSize: 13, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.08em', color: '#64748b' }}>
        {label}
      </div>
      <div style={{ marginTop: 10, fontSize: 28, fontWeight: 800, letterSpacing: '-0.04em' }}>{value}</div>
      <div style={{ marginTop: 8, fontSize: 14, lineHeight: 1.5, color: '#475569' }}>{helper}</div>
    </div>
  );
}

import { unstable_cache } from 'next/cache';
import { getAllProducts } from './db';

export const getCachedProducts = unstable_cache(getAllProducts, ['products'], {
  tags: ['products']
});
